import face_recognition
import numpy as np
import os
import pickle
from sklearn.svm import SVC
from sklearn.preprocessing import LabelEncoder
from PIL import Image

# Configuration for training script
TRAINING_DIR = "employee_photos"
MODEL_PATH = "face_recognition_model.pkl"

def train_facial_recognition_model():
    known_face_encodings = []
    known_face_names = []

    if not os.path.exists(TRAINING_DIR):
        print(f"Error: Training directory '{TRAINING_DIR}' not found.")
        print("Please create it and place employee photos inside, organized by subdirectories for each employee.")
        print("Example: employee_photos/John_Doe/john1.jpg, employee_photos/Jane_Smith/jane1.png")
        return

    print(f"Loading employee photos from '{TRAINING_DIR}'...")

    for employee_name in os.listdir(TRAINING_DIR):
        employee_dir = os.path.join(TRAINING_DIR, employee_name)
        if not os.path.isdir(employee_dir):
            continue

        print(f"  Processing photos for {employee_name}...")
        for filename in os.listdir(employee_dir):
            # Only process image files
            if not (filename.endswith(".jpg") or filename.endswith(".png") or filename.endswith(".jpeg")):
                continue

            image_path = os.path.join(employee_dir, filename)
            try:
                # Load image using face_recognition
                image = face_recognition.load_image_file(image_path)
                # Find all face encodings in the image
                face_encodings = face_recognition.face_encodings(image)

                if len(face_encodings) == 0:
                    print(f"    Warning: No face found in {image_path}. Skipping.")
                    continue
                elif len(face_encodings) > 1:
                    print(f"    Warning: Multiple faces found in {image_path}. Using the first one. Consider using images with a single face for better training.")

                # Add the first found face encoding and its corresponding name
                known_face_encodings.append(face_encodings[0])
                known_face_names.append(employee_name)
                print(f"    Added encoding for {employee_name} from {filename}")

            except Exception as e:
                print(f"    Error processing {image_path}: {e}. Skipping.")

    if not known_face_encodings:
        print("No face encodings found. Training aborted.")
        return

    print("\nTraining classifier...")
    # Encode names to numerical labels
    le = LabelEncoder()
    labels = le.fit_transform(known_face_names)

    # Train a Support Vector Machine classifier with probability estimates
    # LogisticRegression is another good option for probability scores
    classifier = SVC(kernel='linear', probability=True, random_state=42)
    classifier.fit(known_face_encodings, labels)

    # Save the trained model and label encoder
    with open(MODEL_PATH, 'wb') as f:
        pickle.dump((classifier, le), f)

    print(f"\nTraining complete. Model saved to '{MODEL_PATH}'.")
    print(f"Known employees: {', '.join(le.classes_)}")

if __name__ == "__main__":
    # Create a dummy employee_photos directory for demonstration if it doesn't exist
    if not os.path.exists(TRAINING_DIR):
        os.makedirs(os.path.join(TRAINING_DIR, "John_Doe"), exist_ok=True)
        os.makedirs(os.path.join(TRAINING_DIR, "Jane_Smith"), exist_ok=True)
        print(f"Created dummy directory structure '{TRAINING_DIR}'. Please add actual photos inside these employee subdirectories.")
        print(f"Example: {TRAINING_DIR}/John_Doe/pic1.jpg, {TRAINING_DIR}/Jane_Smith/pic2.png")
    
    train_facial_recognition_model()

from flask import Flask, request, jsonify
import face_recognition
import numpy as np
import pickle
import io
from PIL import Image

# Configuration for API
MODEL_PATH = "face_recognition_model.pkl"
DEFAULT_CONFIDENCE_THRESHOLD = 0.6 # Minimum probability for a face to be considered 'recognized'

app = Flask(__name__)

# Load the trained model and label encoder
classifier = None
le = None
try:
    with open(MODEL_PATH, 'rb') as f:
        classifier, le = pickle.load(f)
    print("Model loaded successfully.")
    print(f"Known employees: {', '.join(le.classes_)}")
except FileNotFoundError:
    print(f"Error: Model file '{MODEL_PATH}' not found. Please run train_model.py first.")
except Exception as e:
    print(f"Error loading model: {e}")

@app.route('/recognize', methods=['POST'])
def recognize_face():
    if classifier is None or le is None:
        return jsonify({"error": "Facial recognition model not loaded. Please train the model first by running train_model.py."}), 500

    if 'image' not in request.files:
        return jsonify({"error": "No image file provided. Please upload an image with key 'image'."}), 400

    image_file = request.files['image']
    if not image_file.filename:
        return jsonify({"error": "No selected image file."}), 400

    try:
        # Read the image file into a BytesIO object
        image_bytes = image_file.read()
        pil_image = Image.open(io.BytesIO(image_bytes))
        
        # Convert PIL image to a numpy array (RGB) for face_recognition
        # Ensure it's in the correct format (height, width, channels)
        image_np = np.array(pil_image.convert('RGB'))

        # Find all face locations and face encodings in the uploaded image
        face_locations = face_recognition.face_locations(image_np)
        face_encodings = face_recognition.face_encodings(image_np, face_locations)

        if not face_encodings:
            return jsonify({"message": "No faces found in the image."}), 200

        results = []
        for face_encoding, face_location in zip(face_encodings, face_locations):
            # Predict probabilities for each known class
            probabilities = classifier.predict_proba([face_encoding])[0]
            
            # Get the class names corresponding to the probabilities
            class_names = le.inverse_transform(np.arange(len(le.classes_)))
            
            # Create a dictionary of {employee_name: probability}
            probability_distribution = {name: float(prob) for name, prob in zip(class_names, probabilities)}
            
            # Sort the distribution by probability in descending order
            sorted_distribution = dict(sorted(probability_distribution.items(), key=lambda item: item[1], reverse=True))

            # Get the best match and its confidence
            best_match_name = next(iter(sorted_distribution)) # Get the key of the first item
            best_match_confidence = sorted_distribution[best_match_name]

            # Determine if the face is recognized based on a threshold
            status = "unknown"
            if best_match_confidence >= DEFAULT_CONFIDENCE_THRESHOLD:
                status = "recognized"
            
            # Extract bounding box coordinates (top, right, bottom, left)
            top, right, bottom, left = face_location

            results.append({
                "face_location": {"top": top, "right": right, "bottom": bottom, "left": left},
                "status": status,
                "best_match": {
                    "name": best_match_name,
                    "confidence": float(best_match_confidence) # Ensure float for JSON
                },
                "full_probability_distribution": sorted_distribution
            })

        return jsonify(results), 200

    except Exception as e:
        app.logger.error(f"Error during face recognition: {e}")
        return jsonify({"error": f"An internal server error occurred: {e}"}), 500

if __name__ == '__main__':
    # For development, run with debug=True. In production, use a WSGI server like Gunicorn.
    app.run(host='0.0.0.0', port=5000, debug=True)